// ── Extract ticket from INSERT response ─────────────────────────
const insertRaw    = $('HTTP - Insert Support Ticket').first().json;
const insertedRow  = Array.isArray(insertRaw) ? insertRaw[0] : insertRaw;
const ticket_id    = insertedRow?.id || 'UNKNOWN';
const ticket_status = insertedRow?.status || 'open';

// ── Extract user profile ─────────────────────────────────────────
const profileRaw = $input.first().json;   // result of HTTP - Get User Profile
const profiles   = Array.isArray(profileRaw) ? profileRaw : (profileRaw ? [profileRaw] : []);
const profile    = profiles[0] || {};

// Try common email column names — adjust to match your schema
const userEmail = profile.email
  || profile.user_email
  || profile.contact_email
  || `user-${$('Webhook - Receive Request').first().json.body.user_id}@nova-ops.space`;

const userName = profile.full_name
  || profile.name
  || profile.display_name
  || 'Valued Customer';

// ── Original request ─────────────────────────────────────────────
const body         = $('Webhook - Receive Request').first().json.body;
const issueSummary = (body.issue_summary || 'No summary provided').trim();
const sessionId    = body.session_id || 'N/A';
const appUrl       = $vars.GLOBAL_APP_URL_PROD || 'https://nova-ops.space';

// ── Slack block message ──────────────────────────────────────────
const slackBlocks = [
  {
    type: 'header',
    text: { type: 'plain_text', text: '🚨 Operator Escalation — Human Review Needed', emoji: true }
  },
  {
    type: 'section',
    fields: [
      { type: 'mrkdwn', text: `*User:*\n${userEmail}` },
      { type: 'mrkdwn', text: `*Ticket ID:*\n${ticket_id}` },
      { type: 'mrkdwn', text: `*Session:*\n${sessionId}` },
      { type: 'mrkdwn', text: `*Status:*\n${ticket_status}` }
    ]
  },
  {
    type: 'section',
    text: { type: 'mrkdwn', text: `*Issue Summary:*\n${issueSummary}` }
  },
  {
    type: 'actions',
    elements: [{
      type: 'button',
      text: { type: 'plain_text', text: 'View Ticket', emoji: true },
      url: `${appUrl}/admin/tickets/${ticket_id}`,
      style: 'primary'
    }]
  }
];

// ── User confirmation email ──────────────────────────────────────
const emailSubject = `Your request is being reviewed — Ticket #${ticket_id}`;
const emailBody    = `Hi ${userName},\n\nThank you for reaching out to Nova OPS.\n\nA member of our team is reviewing your request and will respond within 24 hours.\n\nYour ticket reference: ${ticket_id}\n\nIssue logged:\n"${issueSummary}"\n\nIf you have additional information to share, simply reply to this email and include your ticket reference.\n\nNova OPS Support Team\n${appUrl}`;

return [{
  json: {
    ticket_id,
    ticket_status,
    user_id:       body.user_id,
    user_email:    userEmail,
    user_name:     userName,
    issue_summary: issueSummary,
    slack_text:    `Escalation needed — User: ${userEmail} | Issue: ${issueSummary} | Ticket: ${ticket_id}`,
    slack_blocks:  slackBlocks,
    email_subject: emailSubject,
    email_body:    emailBody
  }
}];
